eval("__webpack_require__.r(__webpack_exports__);\n/* harmony export */ __webpack_require__.d(__webpack_exports__, {\n/* harmony export */   getTeamMemberBySlug: () => (/* binding */ getTeamMemberBySlug),\n/* harmony export */   teamMembers: () => (/* binding */ teamMembers)\n/* harmony export */ });\nconst teamMembers = [\n    {\n        slug: \"adrian-thomas-eikmann\",\n        name: \"Adrian Thomas-Eikmann\",\n        djingSince: 2002,\n        email: \"adrian@noteworthydjs.com\",\n        phone: \"971-645-7781\",\n        title: \"DJ and MC\",\n        tagline: \"Decades of experience across a huge variety of event types.\",\n        additionalImages: [\n            \"/img/team/adrian-thomas-eikmann/adrian-thomas-eikmann1-900x600.webp\",\n            \"/img/team/adrian-thomas-eikmann/adrian-thomas-eikmann2-900x600.webp\"\n        ],\n        bio: `Adrian has over 20 years of DJ experience ranging from festivals, clubs, restaurants, art openings, weddings and corporate events. His DJ career began on a day in 1994. His band mates couldn't meet for a rehearsal and the show needed to go on. His background in percussion made the transition from musician to DJ very easy. Learning the basics was a cinch and over time his skills became more well honed. Adrian takes pride in being able to provide the appropriate atmosphere for any occasion. His diverse event experience ranges from performer to promoter to stagehand to volunteer coordinator.\\n\\nHe is also very comfortable with a microphone and is an accomplished MC/speaker who knows how to enhance the event while keeping the focus on you; the true stars of the show.`,\n        image: \"/img/team/adrian-thomas-eikmann.webp\",\n        active: true,\n        yearsDJing: \"20+ years\",\n        languages: \"English\",\n        hometown: \"St. Louis, MO\",\n        currentLocation: \"Portland, OR\",\n        funFact: \"Disc golf competitor with a couple of sponsors.\"\n    },\n    {\n        slug: \"alex-smith\",\n        name: \"Alex Smith\",\n        djingSince: 2019,\n        email: \"alex@noteworthydjs.com\",\n        phone: \"916-579-3565\",\n        title: \"DJ, MC, Photo Booth Host, and Magician\",\n        tagline: \"A lover of all things entertainment.\",\n        additionalImages: [\n            \"/img/team/alex-smith/alex-smith1-900x600.webp\",\n            \"/img/team/alex-smith/alex-smith2-900x600.webp\",\n            \"/img/team/alex-smith/alex-smith3-900x600.webp\",\n            \"/img/team/alex-smith/alex-smith4-900x600.webp\"\n        ],\n        bio: `Alex's love of entertaining started with magic at an early age and he is no stranger when it comes to performing. When he discovered magic at a young age, he immediately developed a love of entertaining. It didn't take long for him to notice how music moved people in very much the same way magic does.\\n\\nHe has worked for many reputable companies and has traveled the world teaching circus, magic, and dance to people of all ages. In addition to working at places such as the San Francisco Opera House, he performed at the 50th Super Bowl as a juggler and magician, and taught magic to children in New Zealand's Auckland City library reading program. This diversity of experience at more than 100 events in front of many thousands of people has equipped him to make events look effortless.`,\n        image: \"/img/team/alex-smith.webp\",\n        active: true,\n        languages: \"English\",\n        funFact: \"Performed at the 50th Super Bowl as a juggler and magician.\",\n        hometown: \"Portland, OR\",\n        currentLocation: \"Portland, OR\",\n        yearsDJing: \"2 years\"\n    },\n    {\n        slug: \"casey-vann\",\n        name: \"Casey Vann\",\n        djingSince: 2007,\n        email: \"casey@noteworthydjs.com\",\n        phone: \"503-888-1216\",\n        title: \"DJ, MC, and Musician\",\n        tagline: \"Coming soon!\",\n        bio: `Keep an eye out here. We should have Casey's bio updated soon!`,\n        image: \"/img/team/casey-vann.webp\",\n        active: true,\n        languages: \"English\",\n        hometown: \"Orlando, FL\",\n        currentLocation: \"Portland, OR\",\n        yearsDJing: \"15+ years\",\n        education: \"University of Portland\",\n        funFact: \"Coaches varsity wrestling.\"\n    },\n    {\n        slug: \"clarissa-pessoa\",\n        name: \"Clarissa Pessoa\",\n        email: \"clarissa@noteworthydjs.com\",\n        phone: \"858-336-5703\",\n        title: \"DJ and MC\",\n        tagline: \"Bringing a Brazilian perspective to every set.\",\n        additionalImages: [\n            \"/img/team/clarissa-pessoa/clarissa-pessoa1-900x600.webp\",\n            \"/img/team/clarissa-pessoa/clarissa-pessoa2-900x600.webp\",\n            \"/img/team/clarissa-pessoa/clarissa-pessoa3-900x600.webp\",\n            \"/img/team/clarissa-pessoa/clarissa-pessoa4-900x600.webp\"\n        ],\n        bio: `Hailing from Brazil, Clarissa draws on her experience from events such as clubs, festivals, weddings, corporate events, and more to keep the dance floor packed. As a Portland transplant, she brings her unmistakable Brazilian perspective to her sets.`,\n        image: \"/img/team/clarissa-pessoa/clarissa-pessoa-800x800.webp\",\n        yearsDJing: \"16 years\",\n        active: true,\n        hometown: \"Brazil\",\n        currentLocation: \"Portland, OR\",\n        languages: \"English, Portuguese\"\n    },\n    {\n        slug: \"hill-picha\",\n        name: \"Hill Picha\",\n        djingSince: 2020,\n        email: \"hill@noteworthydjs.com\",\n        phone: \"503-428-2568\",\n        title: \"DJ, Musician, & Entertainer\",\n        tagline: \"Fire spinner, multi-instrumentalist, and music curator.\",\n        bio: `Hill has been involved in music and performance for over a decade. She is self taught on guitar, piano, ukulele, and loves singing.\\n\\nShe's no stranger to the stage, as she used to perform in an intergalactic space themed marching band that toured across the country. In addition she is a flow arts performer, and has been spinning fire for over 8 years! Once the pandemic hit, she decided to use her expansive taste in music and keen ear to start DJing. What started out as a fun at home activity soon grew to playing small gatherings, then large parties, to playing local festivals and events. Drawing on her experience and knowledge of music, Hill is often heard commenting about how important creating the right experience is.`,\n        image: \"/img/team/hill-picha.webp\",\n        active: true,\n        languages: \"English (and very limited Spanish)\",\n        funFact: \"Fire dancer for 8 years; musician (ukulele, singing, music production).\",\n        hometown: \"Keizer, OR\",\n        currentLocation: \"Portland, OR\",\n        yearsDJing: \"2+ years\",\n        education: \"BS in Environmental Science and Sustainability\"\n    },\n    {\n        slug: \"joe-ebner\",\n        name: \"Joe Ebner\",\n        djingSince: 2008,\n        email: \"info@noteworthydjs.com\",\n        phone: \"503-382-9959\",\n        title: \"DJ, MC, Musician, and Business Owner\",\n        tagline: \"Founder & President of Noteworthy Productions.\",\n        additionalImages: [\n            \"/img/team/joe-ebner/joe-guitar1-900x600.webp\",\n            \"/img/team/joe-ebner/joe-dj1-900x600.webp\",\n            \"/img/team/joe-ebner/joe-guitar2-900x600.webp\",\n            \"/img/team/joe-ebner/joe-bride-900x600.webp\"\n        ],\n        bio: `Joe Ebner is the founder and president of Noteworthy Productions, LLC and has been a performer for most of his life.\\n\\nOregon, Washington, and Arizona have no shortage of DJs and MCs. Joe Ebner — Noteworthy DJs founder and faithful leader — decided long ago to build his business by surrounding himself with the best in the business. Joe is often heard saying \"I'm reminded of an old saying: I don't own the business, the business owns me.\" Great events and great teams are no accident. These are DJs who are very, very good at what they do. Each DJ really loves their work and takes great pride in doing it right and making our clients happy.\\n\\nJoe's experience as a performer spans many roles: DJ, MC, musician, and speaker. He has performed at more than 600 weddings and many hundreds of other events ranging from festivals and concerts to private parties and corporate events.`,\n        image: \"/img/team/joe-ebner.webp\",\n        active: true,\n        hometown: \"Glendale, AZ\",\n        currentLocation: \"Glendale, AZ & Portland, OR\",\n        yearsDJing: \"15+ years\",\n        education: \"MBA, Bachelor's of Science\",\n        languages: \"English\",\n        funFact: \"Musician for 35+ years. Plays guitar, bass, piano, and sings.\"\n    },\n    {\n        slug: \"johnny-zee\",\n        name: \"Johnny Zee\",\n        djingSince: 2019,\n        email: \"johnny@noteworthydjs.com\",\n        phone: \"503-913-2919\",\n        title: \"DJ, MC, Actor, & Musician\",\n        tagline: \"Keeping the focus on the main actors of the occasion.\",\n        additionalImages: [\n            \"/img/team/johnny-zee/johnny-zee1-900x600.webp\",\n            \"/img/team/johnny-zee/johnny-zee2-900x600.webp\"\n        ],\n        bio: `His years of experience bestowed a wealth of knowledge of music, especially up-tempo songs. He has performed across the country to crowds of thousands and small intimate events alike. Johnny is tactful and though he's not shy on the mic, he knows how to keep the focus on the main actors of the occasion. His event history includes weddings, fundraisers, corporate parties, bar mitzvahs, and anniversaries. With his performing experience, he knows what hiccups can happen and how to ensure an event runs smoothly.\\n\\nApart from his knowledge and experience with music and entertaining, Johnny is very comfortable on the mic. He's fond of saying that MCs go a long way to making an event awesome.`,\n        image: \"/img/team/johnny-zee.webp\",\n        active: true,\n        languages: \"English\",\n        hometown: \"Walnut Creek, CA\",\n        currentLocation: \"Portland, OR\",\n        yearsDJing: \"2+ years\",\n        education: \"California College of the Arts\",\n        funFact: \"Printmaker extraordinaire.\"\n    },\n    {\n        slug: \"justin-fetsko\",\n        name: \"Justin Fetsko\",\n        djingSince: 2017,\n        email: \"justin@noteworthydjs.com\",\n        phone: \"503-320-0684\",\n        title: \"DJ, MC, Musician, and Business Owner\",\n        tagline: \"Known for reliability, technical know-how, and reading the room.\",\n        bio: `Justin is no stranger to performance. His passion for music goes back to his early childhood. From music festivals, night clubs, and private parties, his DJing always gets the dance floor filled. He loves to make sure everyone has a good time at his events and is known for his hospitality.\\n\\nWhen he isn't behind the decks you can find Justin working at his \"day job\" running Sticker Ninja in a lifelong quest to make the best stickers in the industry. He also loves traveling in his converted van whenever he has a chance.\\n\\nPeople often book Justin to DJ because he is known for reliability, technical know-how, solid communication, and a knack for reading the room. You can put your mind at ease knowing that he will do everything in his power to make your needs met.`,\n        image: \"/img/team/justin-fetsko.webp\",\n        active: true,\n        languages: \"English\",\n        funFact: \"Runs Sticker Ninja and travels in a converted van.\",\n        hometown: \"Philadelphia, PA\",\n        currentLocation: \"Portland, OR\",\n        yearsDJing: \"5 years\",\n        education: \"Associates Degree in Art Design Technology\"\n    },\n    {\n        slug: \"matt-helvie\",\n        name: \"Matt Helvie\",\n        djingSince: 2009,\n        email: \"matt@noteworthydjs.com\",\n        phone: \"503-597-8121\",\n        title: \"DJ, MC, & Musician\",\n        tagline: \"Professional, flexible, and very easy to work with.\",\n        additionalImages: [\n            \"/img/team/matt-helvie/matt-helvie1-900x600.webp\",\n            \"/img/team/matt-helvie/matt-helvie2-900x600.webp\",\n            \"/img/team/matt-helvie/matt-helvie3-900x600.webp\",\n            \"/img/team/matt-helvie/matt-helvie4-900x600.webp\"\n        ],\n        bio: `Matt draws on his many years of experience to bring a professional and fun atmosphere to your event. He knows details are important to your special day, and works with each client directly to ensure everything goes as good as possible. Like all the DJs at Noteworthy, Matt will work with you start to finish on your event and has a valuable skill set to add to your big day! He's professional, flexible and very easy to work with.`,\n        image: \"/img/team/matt-helvie.webp\",\n        active: true,\n        languages: \"English\",\n        hometown: \"Tangent, OR\",\n        currentLocation: \"Portland, OR\",\n        yearsDJing: \"5+ years\",\n        education: \"Music @ Clackamas Community College\",\n        funFact: \"Singer and guitarist for various Portland-based bands.\"\n    },\n    {\n        slug: \"paul-anderson\",\n        name: \"Paul Anderson\",\n        djingSince: 2005,\n        email: \"paul@noteworthydjs.com\",\n        phone: \"971-645-6017\",\n        title: \"DJ, MC, Musician, Songwriter, & Producer\",\n        tagline: \"One of our most esteemed Wedding DJs.\",\n        bio: `As a longtime musical collaborator with Noteworthy DJs founder Joe Ebner, Paul was keen to join the team and bring his passion for performance to Noteworthy. Having officially joined in 2013, he has amassed accolades from his clients and become a mainstay of the perfect party mix. Always client focused, DJ Paul Anderson is professional, communicative and adaptable to the needs of your event. Like all DJs on the Noteworthy DJs team, Paul is professional, approachable, easy to work with, and very flexible. He works with his clients to ensure they have the best possible experience. Recently wed himself, Paul brings a unique perspective to every wedding he DJs.\\n\\nPaul is no stranger to performing in many different capacities at many types of events. He has been integral in the success of Noteworthy DJs and one of our most esteemed Wedding DJs.`,\n        image: \"/img/team/paul-anderson.webp\",\n        active: true,\n        languages: \"English\",\n        hometown: \"Hahn, Hessen, Germany\",\n        currentLocation: \"Portland, OR\",\n        yearsDJing: \"9+ years\",\n        education: \"Bachelor's of Science\",\n        funFact: \"Bassist, Guitarist, & Singer.\"\n    },\n    {\n        slug: \"rashad-rollins\",\n        name: \"Rashad Rollins\",\n        djingSince: 2014,\n        email: \"rashad@noteworthydjs.com\",\n        phone: \"360-270-7342\",\n        title: \"DJ, MC, & Musician\",\n        tagline: \"It started on the violin.\",\n        additionalImages: [\n            \"/img/team/rashad-rollins/rashad-dj1-900x600.webp\",\n            \"/img/team/rashad-rollins/rashad-dj2-900x600.webp\",\n            \"/img/team/rashad-rollins/rashad-bass-900x600.webp\"\n        ],\n        bio: `For Rashad, it all started in the 3rd grade playing violin in his school's orchestra. Not much time passed before he moved to upright bass and in high school, he picked up the electric guitar for the first time. Music production soon followed. His interest in music shifted gears a bit in college and this was where he got his start as a DJ. His 100%-or-nothing philosophy drove him to dive in head first at perfecting the art of DJing and event coordinating.\\n\\n\"DJ Weddings is so much fun. There is so much love in the air and I feel like it's truly a sacred moment in time. Performances with my band in front of our friends and fans getting to share the moments that we create feels very much the same. They're both great.\"`,\n        image: \"/img/team/rashad-rollins.webp\",\n        active: true,\n        languages: \"English\",\n        funFact: \"Bassist in a funk band.\",\n        hometown: \"Portland, OR\",\n        currentLocation: \"Portland, OR\",\n        yearsDJing: \"4+ years\",\n        education: \"High School Graduate\"\n    },\n    {\n        slug: \"rodney-caldwell\",\n        name: \"Rodney Caldwell\",\n        djingSince: 1999,\n        email: \"rodney@noteworthydjs.com\",\n        phone: \"562-537-8736\",\n        title: \"DJ & MC\",\n        tagline: \"25+ years of DJing experience.\",\n        bio: `Rodney brings over 25 years of DJing experience to every event. Originally from Los Angeles, CA, Rodney now calls Portland, OR home. He is fluent in both English and Spanish.\\n\\nFun fact: Rodney was a professional break dancer for 15 years and designs pro wrestling costumes.`,\n        image: \"/img/team/rodney-caldwell.webp\",\n        active: true,\n        hometown: \"Los Angeles, CA\",\n        currentLocation: \"Portland, OR\",\n        yearsDJing: \"25+ years\",\n        languages: \"English & Spanish\",\n        funFact: \"Professional break dancer for 15 years; designs pro wrestling costumes.\",\n        education: \"University of Portland\"\n    },\n    {\n        slug: \"sonja-corzano\",\n        name: \"Sonja Corzano\",\n        djingSince: 2006,\n        email: \"sonja@noteworthydjs.com\",\n        phone: \"310-600-8296\",\n        title: \"DJ, MC, Dancer, and Model\",\n        tagline: \"Also known as DJ Aquamarine.\",\n        additionalImages: [\n            \"/img/team/sonja-corzano/sonja-corzano1-900x600.webp\",\n            \"/img/team/sonja-corzano/sonja-corzano2-900x600.webp\",\n            \"/img/team/sonja-corzano/sonja-corzano3-900x600.webp\",\n            \"/img/team/sonja-corzano/sonja-corzano4-900x600.webp\"\n        ],\n        bio: `Sonja (aka DJ Aquamarine) has always been known for her fluid moves in the street dance culture and brings that same passion to the turntables and speakers. She has always been a music hunter and hand selects specific tracks for the listener at each event. Her sets are formulated not just to keep the party going, but to create a unique sound experience. Aquamarine's biggest inspirations are Electronic, Hip Hop, Funk, Soul, Jazz, and World Music. So whether it's classic tracks or future sounds, she has an eclectic arsenal of sounds for any occasion.\\n\\nIn addition to DJing, Sonja has also been producing events for a decade. DJing and event planning often require finely-tuned problem-solving skills. Thankfully, Sonja has many years of lessons and loves finding solutions. Creating a setting for an event is her passion.\\n\\nHer experience is expansive, spanning Weddings, Corporate Events, Anniversaries, Holiday parties, New Year's Eve, and more.`,\n        image: \"/img/team/sonja-corzano.webp\",\n        active: true,\n        languages: \"English\",\n        funFact: \"She's a dancer who loves making people dance.\",\n        hometown: \"Los Angeles, CA\",\n        currentLocation: \"Portland, OR\",\n        yearsDJing: \"More than 15\",\n        education: \"East West College\"\n    },\n    {\n        slug: \"dani-renner\",\n        name: \"0nania\",\n        phone: \"952-465-2598\",\n        email: \"dani@noteworthydjs.com\",\n        title: \"DJ\",\n        tagline: \"Making you move with sounds old and new.\",\n        additionalImages: [\n            \"/img/team/dani-renner/dani-renner1-900x600.webp\",\n            \"/img/team/dani-renner/dani-renner2-900x600.webp\",\n            \"/img/team/dani-renner/dani-renner3-900x600.webp\",\n            \"/img/team/dani-renner/dani-renner4-900x600.webp\"\n        ],\n        bio: `0nania is an experienced, all-around DJ based in Portland, OR. She loves mixing together broadly varying genres and curating a dance floor where people can connect. 0nania especially likes house, hip hop, and hyperpop music. She loves to play in local clubs and travels as well.\\n\\n0nania makes sure to play old favorites, but also introduces music you may not have heard before. This DJ wants to make you move!`,\n        image: \"/img/team/dani-renner/dani-renner-800x800.webp\",\n        active: true,\n        hometown: \"Minneapolis, MN\",\n        currentLocation: \"Portland, OR\",\n        yearsDJing: \"4+ years\",\n        education: \"Bachelor of Arts in Theatre Arts, University of Minnesota\",\n        languages: \"English & Spanish\",\n        funFact: \"Her first instrument was trumpet!\"\n    }\n];\nfunction getTeamMemberBySlug(slug) {\n    return teamMembers.find((m)=>m.slug === slug);\n}\n//# sourceURL=[module]\n//# sourceMappingURL=data:application/json;charset=utf-8;base64,\n//# sourceURL=webpack-internal:///(ssr)/./src/data/team.ts\n");

